  // ─── Process books ────────────────────────────────────────────────────────
  const ACTUAL_BOOKS = rawActual
    .map(function (b) {
      var branch = CATEGORY_BRANCH[b.category] || 'science';
      var slug   = b.slug || slugify(b.title);
      return Object.assign({}, b, {
        slug: slug,
        speculative: false,
        branch: branch,
        branchColor: BRANCHES[branch].color,
        description: CATEGORY_DESCRIPTIONS[b.category] || '',
        bookDesc: BOOK_DESCRIPTIONS[slug] || '',
      });
    });

  const SPECULATIVE_BOOKS = rawSpeculative
    .filter(function (b) { return b.rating >= 4.0; })
    .map(function (b) {
      var branch = CATEGORY_BRANCH[b.category] || 'science';
      return Object.assign({}, b, {
        slug: slugify(b.title),
        speculative: true,
        branch: branch,
        branchColor: BRANCHES[branch].color,
        description: CATEGORY_DESCRIPTIONS[b.category] || '',
      });
    });

